def detect_missing_oauth_flow(code: str) -> dict:
    import ast
    tree = ast.parse(code)

    api_calls = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            if node.func.attr in ['get', 'post', 'request']:
                api_calls.append(node)

    missing_auth = []
    for call in api_calls:
        # Check for auth headers or token params
        has_auth = any(
            isinstance(arg, ast.Constant) and 'auth' in str(arg.value).lower() or
            isinstance(arg, ast.Constant) and 'token' in str(arg.value).lower()
            for arg in ast.walk(call)
        )
        if not has_auth:
            missing_auth.append(call)

    return {'missing_oauth_calls': len(missing_auth), 'total_calls': len(api_calls)}

PRIVILEGE_WORDS = ['admin', 'root', 'superuser', 'owner', 'all']
ADMIN_ENDPOINTS = ['/admin', '/users', '/delete', '/modify']

def detect_privilege_escalation(code: str) -> list:
    lines = code.split('\n')
    issues = []
    for i, line in enumerate(lines):
        has_privilege = any(word in line.lower() for word in PRIVILEGE_WORDS)
        has_admin_endpoint = any(endpoint in line for endpoint in ADMIN_ENDPOINTS)
        no_scope_check = 'scope' not in line.lower() and 'permission' not in line.lower()

        if (has_privilege or has_admin_endpoint) and no_scope_check:
            issues.append({
                'line': i + 1,
                'code': line.strip(),
                'risk': 'potential_privilege_escalation'
            })
    return issues

