import os
from dotenv import load_dotenv

class SecureAuth:
    def __init__(self):
        load_dotenv()

    @property
    def api_key(self):
        key = os.getenv('API_KEY')
        if not key:
            raise ValueError('API_KEY not set in environment')
        return key

    def get_headers(self):
        return {'Authorization': f'Bearer {self.api_key}'}

