import requests
from requests_oauthlib import OAuth2Session

class OAuthManager:
    def __init__(self, client_id, client_secret, token_url):
        self.client_id = client_id
        self.client_secret = client_secret
        self.token_url = token_url
        self.token = None

    def ensure_valid_token(self):
        if not self.token or self.token.get('expires_at', 0) < time.time() + 60:
            self.token = self._refresh_token()

    def _refresh_token(self):
        oauth = OAuth2Session(self.client_id)
        token = oauth.fetch_token(
            self.token_url,
            client_secret=self.client_secret,
            refresh_token=self.token.get('refresh_token')
        )
        token['expires_at'] = time.time() + token['expires_in']
        return token

    def make_request(self, method, url, **kwargs):
        self.ensure_valid_token()
        return requests.request(method, url, headers={'Authorization': f'Bearer {self.token["access_token"]}'}, **kwargs)

from typing import Dict, List

class PermissionGuard:
    def __init__(self, user_scopes: List[str]):
        self.user_scopes = set(user_scopes)

    def require_scopes(self, required_scopes: List[str], operation: str):
        missing = set(required_scopes) - self.user_scopes
        if missing:
            raise PermissionError(f'Missing scopes for {operation}: {missing}')

    def admin_only(func):
        @wraps(func)
        def wrapper(self, *args, **kwargs):
            self.require_scopes(['admin'], func.__name__)
            return func(self, *args, **kwargs)
        return wrapper

